2	 * Executor Registry
3	 * Replaces the monolithic if/else chain in workflow-executor.ts with a clean registry pattern.
4	 * Each node type registers an executor that handles its execution logic.
5	 */
6	
7	import type { nodes } from "@/db/schema";
8	import type { ExecutionItem } from "@/types/execution";
9	import type { connections } from "@/db/schema";
10	
11	export interface ExecutionContext {
12	  organizationId: string;
13	  workflowId: string;
14	  workflowName: string;
15	  workflowConnections: (typeof connections.$inferSelect)[];
16	  nodeMap: Map<string, typeof nodes.$inferSelect>;
17	  nodeOutputs: Map<string, ExecutionItem[]>;
18	  utilities: Map<string, { label: string; exports: Record<string, any>; code: string }>;
19	  typeDefinitions?: string;
20	  /** Callback to execute a subworkflow */
21	  executeWorkflow?: (workflowId: string, organizationId: string, triggerData?: Record<string, unknown>) => Promise<any>;
22	}
23	
24	export interface NodeExecutor {
25	  execute(
26	    node: typeof nodes.$inferSelect,
27	    inputItems: ExecutionItem[],
28	    context: ExecutionContext
29	  ): Promise<ExecutionItem[]>;
30	}
31	
32	/**
33	 * Result for conditional nodes (IF, Switch) that route to different outputs
34	 */
35	export interface ConditionalExecutorResult {
36	  outputs: Record<string, ExecutionItem[]>;
37	  allItems: ExecutionItem[];
38	}
39	
40	export interface ConditionalNodeExecutor {
41	  executeConditional(
42	    node: typeof nodes.$inferSelect,
43	    inputItems: ExecutionItem[],
44	    context: ExecutionContext
45	  ): ConditionalExecutorResult;
46	}
47	
48	function isConditionalExecutor(executor: NodeExecutor | ConditionalNodeExecutor): executor is ConditionalNodeExecutor {
49	  return 'executeConditional' in executor;
50	}
51	
52	class ExecutorRegistry {
53	  private executors = new Map<string, NodeExecutor>();
54	  private conditionalExecutors = new Map<string, ConditionalNodeExecutor>();
55	  private passThroughTypes = new Set<string>();
56	
57	  register(nodeType: string, executor: NodeExecutor): void {
58	    this.executors.set(nodeType, executor);
59	  }
60	
61	  registerConditional(nodeType: string, executor: ConditionalNodeExecutor): void {
62	    this.conditionalExecutors.set(nodeType, executor);
63	  }
64	
65	  registerPassThrough(nodeType: string): void {
66	    this.passThroughTypes.add(nodeType);
67	  }
68	
69	  get(nodeType: string): NodeExecutor | undefined {
70	    return this.executors.get(nodeType);
71	  }
72	
73	  getConditional(nodeType: string): ConditionalNodeExecutor | undefined {
74	    return this.conditionalExecutors.get(nodeType);
75	  }
76	
77	  isPassThrough(nodeType: string): boolean {
78	    return this.passThroughTypes.has(nodeType);
79	  }
80	
81	  has(nodeType: string): boolean {
82	    return this.executors.has(nodeType) || this.conditionalExecutors.has(nodeType) || this.passThroughTypes.has(nodeType);
83	  }
84	}
85	
