325	// Helper to build predecessor outputs map (used by code/webhookResponse nodes)
326	function buildPredecessorOutputs(
327	  nodeId: string,
328	  ctx: ExecutionContext
329	): Map<string, { nodeLabel: string; output: ExecutionItem[] }> {
330	  const predecessorOutputs = new Map<string, { nodeLabel: string; output: ExecutionItem[] }>();
331	  const visited = new Set<string>();
332	  const queue = [nodeId];
333	
334	  while (queue.length > 0) {
335	    const currentId = queue.shift()!;
336	    if (visited.has(currentId)) continue;
337	    visited.add(currentId);
338	
339	    const incomingConns = ctx.workflowConnections.filter(c => c.targetNodeId === currentId);
340	    for (const conn of incomingConns) {
341	      const sourceNodeId = conn.sourceNodeId;
342	      if (!visited.has(sourceNodeId)) {
343	        const sourceOutput = ctx.nodeOutputs.get(sourceNodeId);
344	        const sourceNode = ctx.nodeMap.get(sourceNodeId);
345	        if (sourceOutput && sourceNode) {
346	          predecessorOutputs.set(sourceNodeId, {
347	            nodeLabel: sourceNode.label || `Node ${sourceNodeId.substring(0, 8)}`,
348	            output: sourceOutput,
349	          });
350	        }
351	        queue.push(sourceNodeId);
352	      }
353	    }
354	  }
355	
356	  return predecessorOutputs;
357	}
