 * Executor Registry
 * Replaces the monolithic if/else chain in workflow-executor.ts with a clean registry pattern.
 * Each node type registers an executor that handles its execution logic.
 */

import type { nodes } from "@/db/schema";
import type { ExecutionItem } from "@/types/execution";
import type { connections } from "@/db/schema";

export interface ExecutionContext {
  organizationId: string;
  workflowId: string;
  workflowName: string;
  workflowConnections: (typeof connections.$inferSelect)[];
  nodeMap: Map<string, typeof nodes.$inferSelect>;
  nodeOutputs: Map<string, ExecutionItem[]>;
  utilities: Map<string, { label: string; exports: Record<string, any>; code: string }>;
  typeDefinitions?: string;
  /** Callback to execute a subworkflow */
  executeWorkflow?: (workflowId: string, organizationId: string, triggerData?: Record<string, unknown>) => Promise<any>;
}

export interface NodeExecutor {
  execute(
    node: typeof nodes.$inferSelect,
    inputItems: ExecutionItem[],
    context: ExecutionContext
  ): Promise<ExecutionItem[]>;
}

/**
 * Result for conditional nodes (IF, Switch) that route to different outputs
 */
export interface ConditionalExecutorResult {
  outputs: Record<string, ExecutionItem[]>;
  allItems: ExecutionItem[];
}

export interface ConditionalNodeExecutor {
  executeConditional(
    node: typeof nodes.$inferSelect,
    inputItems: ExecutionItem[],
    context: ExecutionContext
  ): ConditionalExecutorResult;
}

function isConditionalExecutor(executor: NodeExecutor | ConditionalNodeExecutor): executor is ConditionalNodeExecutor {
  return 'executeConditional' in executor;
}

class ExecutorRegistry {
  private executors = new Map<string, NodeExecutor>();
  private conditionalExecutors = new Map<string, ConditionalNodeExecutor>();
  private passThroughTypes = new Set<string>();

  register(nodeType: string, executor: NodeExecutor): void {
    this.executors.set(nodeType, executor);
  }

  registerConditional(nodeType: string, executor: ConditionalNodeExecutor): void {
    this.conditionalExecutors.set(nodeType, executor);
  }

  registerPassThrough(nodeType: string): void {
    this.passThroughTypes.add(nodeType);
  }

  get(nodeType: string): NodeExecutor | undefined {
    return this.executors.get(nodeType);
  }

  getConditional(nodeType: string): ConditionalNodeExecutor | undefined {
    return this.conditionalExecutors.get(nodeType);
  }

  isPassThrough(nodeType: string): boolean {
    return this.passThroughTypes.has(nodeType);
  }

  has(nodeType: string): boolean {
    return this.executors.has(nodeType) || this.conditionalExecutors.has(nodeType) || this.passThroughTypes.has(nodeType);
  }
}

