// Helper to build predecessor outputs map (used by code/webhookResponse nodes)
function buildPredecessorOutputs(
  nodeId: string,
  ctx: ExecutionContext
): Map<string, { nodeLabel: string; output: ExecutionItem[] }> {
  const predecessorOutputs = new Map<string, { nodeLabel: string; output: ExecutionItem[] }>();
  const visited = new Set<string>();
  const queue = [nodeId];

  while (queue.length > 0) {
    const currentId = queue.shift()!;
    if (visited.has(currentId)) continue;
    visited.add(currentId);

    const incomingConns = ctx.workflowConnections.filter(c => c.targetNodeId === currentId);
    for (const conn of incomingConns) {
      const sourceNodeId = conn.sourceNodeId;
      if (!visited.has(sourceNodeId)) {
        const sourceOutput = ctx.nodeOutputs.get(sourceNodeId);
        const sourceNode = ctx.nodeMap.get(sourceNodeId);
        if (sourceOutput && sourceNode) {
          predecessorOutputs.set(sourceNodeId, {
            nodeLabel: sourceNode.label || `Node ${sourceNodeId.substring(0, 8)}`,
            output: sourceOutput,
          });
        }
        queue.push(sourceNodeId);
      }
    }
  }

  return predecessorOutputs;
}
